### 2. SQLite Introspection
```rust
pub async fn introspect_sqlite(conn: &impl Connection) -> Result<DatabaseSchema> {
    let mut schema = DatabaseSchema::new(Dialect::Sqlite);

    // List all tables
    let tables = conn.query(
        "SELECT name FROM sqlite_master WHERE type='table' AND name NOT LIKE 'sqlite_%'",
        &[]
    ).await?;

    for table_row in tables {
        let table_name: String = table_row.get("name")?;
        let mut table = TableSchema::new(&table_name);

        // Get column info
        let cols = conn.query(
            &format!("PRAGMA table_info('{}')", table_name),
            &[]
        ).await?;

        for col in cols {
            table.columns.push(ColumnSchema {
                name: col.get("name")?,
                sql_type: col.get("type")?,
                nullable: col.get::<i32>("notnull")? == 0,
                default: col.get("dflt_value").ok(),
                auto_increment: false, // Check via AUTOINCREMENT in CREATE
                comment: None,
                parsed_type: parse_sql_type(&col.get::<String>("type")?),
            });

            if col.get::<i32>("pk")? > 0 {
                table.primary_key = Some(PrimaryKeySchema {
                    name: None,
                    columns: vec![col.get("name")?],
                });
            }
        }

        // Get foreign keys
        let fks = conn.query(
            &format!("PRAGMA foreign_key_list('{}')", table_name),
            &[]
        ).await?;

        for fk in fks {
            table.foreign_keys.push(ForeignKeySchema {
                name: None,
                columns: vec![fk.get("from")?],
                referenced_table: fk.get("table")?,
                referenced_columns: vec![fk.get("to")?],
                on_delete: fk.get("on_delete").ok(),
                on_update: fk.get("on_update").ok(),
            });
        }

        // Get indexes
        let indexes = conn.query(
            &format!("PRAGMA index_list('{}')", table_name),
            &[]
        ).await?;

        for idx in indexes {
            let idx_name: String = idx.get("name")?;
            let idx_info = conn.query(
                &format!("PRAGMA index_info('{}')", idx_name),
                &[]
            ).await?;

            table.indexes.push(IndexSchema {
                name: idx_name,
                columns: idx_info.iter().map(|r| r.get("name").unwrap()).collect(),
                unique: idx.get::<i32>("unique")? == 1,
                index_type: None,
            });
        }

        schema.tables.insert(table_name, table);
    }

    Ok(schema)
}
